"use client";

import { useState } from "react";

export default function Home() {
  const [noCount, setNoCount] = useState(0);
  const [noStyle, setNoStyle] = useState({});
  const [showHonestNo, setShowHonestNo] = useState(false);

  const moveNoButton = () => {
    if (showHonestNo) return;

    const nextCount = noCount + 1;
    setNoCount(nextCount);

    const x = Math.floor(Math.random() * 220) - 110;
    const y = Math.floor(Math.random() * 120) - 60;
    setNoStyle({
      transform: `translate(${x}px, ${y}px)`,
    });

    if (nextCount >= 4) {
      setShowHonestNo(true);
      setNoStyle({});
    }
  };

  return (
    <main
      style={{
        textAlign: "center",
        padding: "50px 20px",
        minHeight: "100vh",
        fontFamily: "Arial, sans-serif",
      }}
    >
      <h1>Hai, [Nina]</h1>
      <p>Ada sesuatu yang ingin aku sampaikan...</p>

      <section style={{ maxWidth: "520px", margin: "0 auto 24px auto" }}>
        <h2>Beberapa hal yang aku inget</h2>
        <ul style={{ textAlign: "left" }}>
          <li>Momen pertama kita ngobrol</li>
          <li>Hal kecil yang bikin aku nyaman</li>
          <li>Cara kamu bikin hari biasa jadi spesial</li>
        </ul>
      </section>

      <section>
        <h2>Jujur ya...</h2>
        <p>Aku suka kamu.</p>
        <p>
          Will u be my girlfriend?
        </p>

        <div
          style={{
            display: "flex",
            justifyContent: "center",
            alignItems: "center",
            gap: "12px",
            flexWrap: "wrap",
            marginTop: "12px",
            minHeight: "70px",
          }}
        >
          <button
            onClick={() => alert("Aku seneng banget! Makasih udah bilang iya 😊")}
            style={{
              padding: "10px 18px",
              borderRadius: "8px",
              border: "none",
              background: "#22c55e",
              color: "white",
              cursor: "pointer",
              fontWeight: 600,
            }}
          >
            Yes
          </button>

          {!showHonestNo ? (
            <button
              onMouseEnter={moveNoButton}
              onClick={moveNoButton}
              style={{
                padding: "10px 18px",
                borderRadius: "8px",
                border: "1px solid #e11d48",
                background: "white",
                color: "#e11d48",
                cursor: "pointer",
                transition: "transform 0.2s ease",
                ...noStyle,
              }}
            >
              No
            </button>
          ) : (
            <button
              onClick={() => alert("Makasih sudah jujur. Aku tetap menghargai perasaan kamu.")}
              style={{
                padding: "10px 18px",
                borderRadius: "8px",
                border: "1px solid #64748b",
                background: "#f8fafc",
                color: "#334155",
                cursor: "pointer",
              }}
            >
              Belum dulu
            </button>
          )}
        </div>

        {!showHonestNo ? (
          <p style={{ marginTop: "10px", color: "#64748b", fontSize: "14px" }}>
            Tombol No lagi malu-malu 😄
          </p>
        ) : (
          <p style={{ marginTop: "10px", color: "#64748b", fontSize: "14px" }}>
            Apapun jawaban kamu, aku hargai.
          </p>
        )}
      </section>
    </main>
  );
}